import { environmentSettingsClient } from '@dynatrace-sdk/client-platform-management-service';

import { DEFAULT_COUNTRY_CODE } from '../constants.js';

export const getTenantCountryCode = () =>
  environmentSettingsClient
    .getEnvironmentSettings({})
    .then(({ countryCode }) => countryCode ?? DEFAULT_COUNTRY_CODE)
    .catch((_) => DEFAULT_COUNTRY_CODE);
